import{_ as b,o as t,c as a,j as r,a as p,a1 as l}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"X因子","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/5.通用类/X因子.md","filePath":"4.资源分区/2.改造与功法/改造/5.通用类/X因子.md"}'),n={name:"4.资源分区/2.改造与功法/改造/5.通用类/X因子.md"};function s(d,e,o,A,i,_){return t(),a("div",null,[...e[0]||(e[0]=[r("h1",{id:"x因子",tabindex:"-1"},[p("X因子 "),r("a",{class:"header-anchor",href:"#x因子","aria-label":'Permalink to "X因子"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),l('<h1 id="x因子-1" tabindex="-1">X因子 <a class="header-anchor" href="#x因子-1" aria-label="Permalink to &quot;X因子&quot;">​</a></h1><p>X因子</p><p>基于从「谜之女主角X」中抽出的X因子，再通过禁忌的魔术炼成进行的改造。</p><p>仅限女性强化该改造。<br> PS：进行该改造的轮回者容貌会不可逆转的变为武内脸。</p><p>D级 D+600<br> “魔力转换炉Alter莉雅反应炉成功植入，无排异反应......”<br> 【Alter力】：<br> 开启名为Alter力的通用能量池，视为魔力变体，关键词为智力+耐力。并且耐力上的每个附加成功都会提高3点能量池上限。</p><p>魔力转换炉Alter莉雅反应炉能够将隐藏在体内的Alter元素结晶作为触媒，并把卡路里变换为魔力，同时也赋予强化者强大的感知能力，并确保宿主能在宇宙级恶劣环境下也能做到正常的休息。<br> 因此，强化者的食物需求将变为正常人的3倍，如果连续两日没有进食充足的食物时，Alter无法使用（这时视为Alter力为空）。同时这也意味着当Alter力不为空时，强化者获得自适应长休，全环境呼吸，黑暗视觉。</p><p>C级 C+1200<br> 魔力转换炉Alter莉雅反应炉和肉体进一步链接，诞生许多神奇的能力......</p><p>【邪圣剑死之胜利剑】：<br> 越是帅气的武器越是不强，这似乎是宇宙共通的规则，还是平淡无奇的长剑最棒了。<br> 但或许，也会有在危机时刻解封隐藏力量的设定？<br> 效果：<br> 自由动作并支付6点Alter力使用，手中的剑型武器将转化为散发赤色魔力的剑杖（即双头光剑）或者电锯之类的样子，强大的魔力足以撕裂空间，突然变化的武器也会使得敌人难以应对。<br> 此时，你使用变化后的武器进行的格挡防御获得4dp技艺加值，你可以该武器进行传送攻击，且该武器攻击时的触及范围提升12m，这视为c级时空来源的传送效果。</p><p>【王之看不见的手】：<br> 一切变化的背后往往有一只看不见的手。。。。。<br> 效果：<br> 消耗6点Alter力，以移动动作使用。<br> 选择触及范围内的一名角色，只要该角色处于你的触及范围内，你就对其提供全遮蔽，这是一个c级心灵来源的效果，持续时间为一场景。<br> 选择完毕后，自身的攻击检定再获得5高速，持续时间为一场景。</p><p>B级 B+2400<br> ∞的力量已经初步在你的身体中显现，你体内的魔力炉在此时已经可以更名为“XX·Alter的魔力转换炉Alter莉雅反应炉”</p><p>【量子甲胄 】：<br> 通过Alter力和魔力炉对铠甲进行重新编纂，覆盖，将圣枪甲胄阿瓦隆的概念融入身上的防具之中。阿瓦隆的概念将持续治疗持有者的伤势，守护持有者的精神，当然不是所有的盔甲都能承受圣枪甲胄的能力。<br> 需要装备等级C及以上，占据躯干位的防具才能启动以下效果。<br> 效果：在原本的防具效果仍生效时，你可以获得2快速医疗【24医疗点】、1异常点治疗【24异常点数】，同时你获得一个大小约未10立方米的储物空间。存入与取出其中的物品都是一个移动动作。</p><p>【武恶之极限】：<br> 生存便是究极之恶。在银河中留下生命的爪痕，将一切的宝物，还有甜食什么的收入囊中吧。<br> 效果：<br> 你的攻击附带一点不可豁免的精神束缚点数。</p><p>同时这名为生存的恶是没有极限的，与你为敌将需要莫大的勇气：每部影片结束后，如果你完成了一场同等级的战斗并胜利，【武恶之极限】所附带的精神束缚点数将再增加一点</p><p>A级：A+4800<br> 【重力操控】：<br> 构筑魔术性质的假想黑洞，自如地操纵重力。但不知为何，唯独做不到让自己的体重变轻。<br> 动作：标准<br> 持续：一场景<br> 射程：敏感范围<br> 范围：黑洞为中心，感知*10米的圆。<br> 目标：范围内所有单位。<br> 效果：<br> 选择射程范围内一点，在一轮后的目标点生成一个假想黑洞。<br> 当假想黑洞生成后，你可以一个花招动作操控黑洞对范围内产生如下影响，每一个选项在一轮内只能使用一次，当选择一个选项以后，其他选项将会失效：<br> 1、你能选择这一范围内的重力下落方向，令其他受影响单位向该方向下落，在下落途中的单位将处于A级别环境来源的浮空状态。<br> 2、令这一范围内的受影响单位处于A级环境来源的困难地形状态。<br> 3、令这一范围内的受影响单位处于A级环境来源的时间延缓状态。<br> 同一时间只会存在一个假想黑洞。</p><p>【刹那无影剑】：<br> Alter莉雅反应炉临界突破！在我这暗黑光芒下，回归基本粒子吧！黑龙双克胜利剑！<br> 效果：<br> 你获得8点只能使用本改造效果和下属技能树的ap。</p><p>x因子下属技能树：</p><p>【Alter力基础用法】：<br> 价格：D+500<br> 【宇宙尺度】：角色的寿命不会因为时间而自然流逝<br> 【宇宙生存】：自由动作并消耗2点Alter力，直到下回合自己行动时，获得4点力场防御。</p><p>【Alter力闪电】：<br> 价格：C+1000<br> 动作：标准<br> 能耗：6点Alter力<br> 射程：15m锥形<br> 目标： 范围内所有敌方单位<br> 效果：<br> 进行一次以敏捷为主属性的近战白刃攻击，这次攻击获得4dp技艺加值，将这次攻击转化为15m锥形的范围伤害，伤害性质为精神伤害，意志豁免，该攻击获得【法破】。画风类比原力闪电，不过是暗红色。</p><p>【Alter力联结】：<br> 价格：C+1000<br> 效果：<br> 强大的Alter力可以让你在死亡前也保持足够的战斗力，此刻你不会因为伤势而昏迷。<br> 可以使用Alter力为自己与其他人构建心灵链接，可以与另一单位（需自愿）进行无延迟，无范围的心灵沟通。</p><p>【黑龙双克胜利剑】：<br> 价格：B+2000<br> 动作：标准动作<br> 能耗：10点Alter力<br> 射程：触及范围<br> 目标：一人<br> 效果：<br> 进行一次白刃检定，你可以将成功数分配为【高速】，【破甲】，【威猛】，【破魔】（每种转化上限为5点）。<br> 随后进行一次白刃攻击，这次白刃攻击获得8dp技艺加值，b级措手不及，【能量武器】且攻击目标承受如受到8次攻击般的多次攻击减值。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',22)])])}const m=b(n,[["render",s]]);export{h as __pageData,m as default};
